import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAppContext } from '../context/AppContext';
import toast from 'react-hot-toast';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAppContext();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const result = await login(email, password);
      
      if (result.success) {
        // Get business ID from response
        const businessData = result.data?.business || result.data?.data?.business;
        const businessId = businessData?.id || result.data?.data?.id;
        
        console.log('✅ Login successful!');
        console.log('📝 Business data:', businessData);
        console.log('📝 Business ID:', businessId);
        
        // Store business ID in localStorage
        if (businessId) {
          localStorage.setItem('businessId', businessId);
          console.log('✅ Business ID stored in localStorage:', businessId);
        } else {
          console.warn('⚠️ No business ID found in response');
          // Use the demo business ID as fallback
          const demoBusinessId = '59f7d90e-2d0c-42d5-9389-b4712c29a154';
          localStorage.setItem('businessId', demoBusinessId);
          console.log('✅ Using demo business ID:', demoBusinessId);
        }
        
        // Store user data
        if (businessData) {
          localStorage.setItem('user', JSON.stringify(businessData));
        }
        
        // Verify storage
        console.log('🔍 Verification - businessId in localStorage:', localStorage.getItem('businessId'));
        
        navigate('/dashboard');
        toast.success('Welcome back!');
      } else {
        toast.error(result.error || 'Login failed');
      }
    } catch (error) {
      console.error('Login error:', error);
      toast.error(error.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  // Demo login for testing
  const handleDemoLogin = () => {
    setEmail('demo@example.com');
    setPassword('password123');
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <h1>AI Customer Support</h1>
          <p>Sign in to your account</p>
        </div>
        
        <form onSubmit={handleSubmit} className="login-form">
          <div className="form-group">
            <label>Email Address</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
            />
          </div>
          
          <div className="form-group">
            <label>Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
            />
          </div>
          
          <button type="submit" className="btn-primary" disabled={loading}>
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
          
          <button 
            type="button" 
            className="btn-secondary demo-btn" 
            onClick={handleDemoLogin}
          >
            Use Demo Credentials
          </button>
        </form>
        
        <div className="login-footer">
          <p>Demo: demo@example.com / password123</p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
